_check_root() {
  if [ "$(id -u)" -ne 0 ]; then
    echo "This installer must be run as root." >&2
    exit 1
  fi
}

_check_deps() {
  local missing=""
  ! command -v whiptail >/dev/null 2>&1 && missing="$missing libnewt"
  ! command -v git >/dev/null 2>&1 && missing="$missing git"
  ! command -v sudo >/dev/null 2>&1 && missing="$missing sudo"
  ! pacman -Qi base-devel >/dev/null 2>&1 && missing="$missing base-devel"

  if [ -z "$missing" ]; then
    return 0
  fi

  if command -v whiptail >/dev/null 2>&1; then
    whiptail --title "Missing Dependencies" --yesno \
      "The following packages are required:\n\n$missing\n\nInstall them now?" \
      12 50 || exit 1
  else
    echo "Missing dependencies:$missing"
    printf "Install now? [Y/n] "
    read -r answer
    case "$answer" in
      n|N|no|NO) exit 1 ;;
    esac
  fi

  # shellcheck disable=SC2086
  pacman -S --needed --noconfirm $missing
}

_install_aur_helper() {
  local helper="$1" user="$2"

  case "$helper" in
    yay|paru) ;;
    *) echo "Invalid AUR helper: $helper" >&2; return 1 ;;
  esac
  if ! printf '%s' "$user" | grep -qE '^[a-z_][a-z0-9_-]*\$?$'; then
    echo "Invalid username: $user" >&2
    return 1
  fi

  command -v "$helper" >/dev/null 2>&1 && return 0

  if [ "$(id -un)" != "$user" ]; then
    if ! id "$user" >/dev/null 2>&1; then
      useradd -m "$user" 2>/dev/null || true
    fi
    mkdir -p /etc/sudoers.d
    cat > "/etc/sudoers.d/updatebtw-$user-build" << SUDOEOF
Defaults!/usr/bin/pacman log_output
$user ALL=(root) NOPASSWD: /usr/bin/pacman
SUDOEOF
    chmod 440 "/etc/sudoers.d/updatebtw-$user-build"
  fi

  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build"' EXIT

  local helper_tmp
  # Clean up any stale directories from previous failed runs
  rm -rf /tmp/updatebtw-"$helper".* 2>/dev/null || true
  helper_tmp="$(mktemp -d "/tmp/updatebtw-$helper.XXXXXX")"
  chown "$user:$user" "$helper_tmp"
  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build"; rm -rf "$helper_tmp"' EXIT

  local build_script
  build_script="$(mktemp /tmp/updatebtw-build.XXXXXX)"
  cat > "$build_script" << BUILDEOF
#!/bin/sh
set -e
HELPER="\$1"
HELPER_TMP="\$2"
git clone --depth=1 "https://aur.archlinux.org/\$HELPER.git" "\$HELPER_TMP"
cd "\$HELPER_TMP"

# Install build dependencies as root before running makepkg
# makepkg -makedepends requires sudo, which the aur user may not have
_deps="\$(makepkg --printsrcinfo 2>/dev/null | sed -n 's/^\tmakedepends = //p' | tr '\n' ' ')"
if [ -n "\$_deps" ]; then
  sudo pacman -S --needed --noconfirm \$_deps 2>/dev/null || true
fi

makepkg --noconfirm
BUILDEOF
  chmod 755 "$build_script"
  trap 'rm -f "/etc/sudoers.d/updatebtw-$user-build" "$build_script"; rm -rf "$helper_tmp"' EXIT

  # PKGBUILD review prompt before building (H3)
  if [ -t 0 ] && [ "${UPDATEBTW_AUTO_INSTALL_AUR:-}" != "1" ]; then
    echo "==> AUR helper '$helper' will be built from the AUR."
    echo "    Review the PKGBUILD before proceeding:"
    echo "    https://aur.archlinux.org/cgit/aur.git/tree/PKGBUILD?h=$helper"
    printf "    Continue? [y/N] "
    read -r _aur_answer
    case "$_aur_answer" in
      y|Y) ;;
      *) echo "Aborted."; return 1 ;;
    esac
  fi

  if [ "$(id -un)" = "$user" ]; then
    sh "$build_script" "$helper" "$helper_tmp"
  else
    su - "$user" -s /bin/sh -- "$build_script" "$helper" "$helper_tmp"
  fi

  if [ -f "$helper_tmp/PKGBUILD" ]; then
    local pkgbuild_hash
    pkgbuild_hash="$(sha256sum "$helper_tmp/PKGBUILD" | awk '{print $1}')"
    echo "PKGBUILD SHA256: $pkgbuild_hash"
    echo "Verify at: https://aur.archlinux.org/cgit/aur.git/tree/PKGBUILD?h=$helper"
  fi

  sudo pacman -U --noconfirm "$helper_tmp"/*.pkg.tar.* && printf "Installed %s\n" "$helper" || printf "Warning: failed to install %s\n" "$helper"

  rm -f "$build_script"
  command -v "$helper" >/dev/null 2>&1
}

_setup_aur_user() {
  local user="$1"
  [ -n "$user" ] || return 1

  if ! id "$user" >/dev/null 2>&1; then
    useradd -m "$user" 2>/dev/null || true
  fi

  rm -f "/etc/sudoers.d/updatebtw-$user-build" 2>/dev/null || true
  rm -f "/etc/sudoers.d/updatebtw-$user" 2>/dev/null || true
  mkdir -p /etc/sudoers.d
  cat > "/etc/sudoers.d/updatebtw-$user" << SUDOEOF
Defaults!/usr/bin/pacman log_output
$user ALL=(root) NOPASSWD: /usr/bin/pacman
SUDOEOF
  chmod 440 "/etc/sudoers.d/updatebtw-$user"
}

# === config module ===
# updatebtw config module

UPDATERBTW_CONFIG="${UPDATERBTW_CONFIG:-/etc/updatebtw/updatebtw.conf}"
AUR_USER="${AUR_USER:-aur_builder}"
FLATPAK_USER="${FLATPAK_USER:-${AUR_USER:-aur_builder}}"

_allowed_config_keys="AUR_HELPER UPDATE_FREQUENCY UPDATE_TIME RUN_AT_BOOT ENABLE_REFLECTOR REFLECTOR_COUNTRY REFLECTOR_PROTOCOL REFLECTOR_INTERVAL SILENT_BOOT AUR_USER FLATPAK_USER BLACKLIST_MODULES"

# Strict allowlist of characters permitted in config values.
# Covers: alphanumerics, _, ., /, space, :, @, comma, +, -
# Excludes: $ ` ; & | ( ) { } ! < > ' " [ ] \ ~ # % ^ * ?
_safe_value_pattern='^[a-zA-Z0-9_./ :@,+.-]*$'

_safe_read_config() {
  local cfg="$1"

  if [ -L "$cfg" ]; then
    echo "updatebtw: config $cfg is a symlink, refusing" >&2
    return 1
  fi

  # Open fd FIRST — no prior existence check eliminates TOCTOU window.
  # If the file doesn't exist, exec fails and we return 0 (nothing to read).
  exec 8< "$cfg" 2>/dev/null || return 0

  # Resolve the opened fd to its real path — this is our ground truth.
  local real_path perms owner
  real_path="$(readlink -f /proc/self/fd/8 2>/dev/null)" || { exec 8<&-; return 1; }

  # Validate permissions via the opened fd (not the original path).
  perms="$(stat -L -c '%a' /proc/self/fd/8 2>/dev/null)" || { exec 8<&-; return 1; }
  if [ "$perms" != "600" ] && [ "$perms" != "400" ]; then
    echo "updatebtw: config has unsafe permissions ($perms), expected 600 or 400" >&2
    exec 8<&-
    return 1
  fi

  owner="$(stat -L -c '%U' /proc/self/fd/8 2>/dev/null)" || { exec 8<&-; return 1; }
  if [ "$owner" != "root" ]; then
    echo "updatebtw: config is not owned by root (owned by $owner)" >&2
    exec 8<&-
    return 1
  fi

  local line key value
  while IFS= read -r line <&8; do
    case "$line" in
      ""|\#*) continue ;;
    esac
    key="${line%%=*}"
    key="$(printf '%s' "$key" | tr -d '[:space:]')"
    local allowed=false k
    for k in $_allowed_config_keys; do
      if [ "$key" = "$k" ]; then
        allowed=true
        break
      fi
    done
    if ! $allowed; then
      echo "updatebtw: config $cfg contains unknown key: $key" >&2
      exec 8<&-
      return 1
    fi

    # Extract value: strip key= and surrounding quotes
    value="${line#*=}"
    # Remove leading/trailing double quotes if present
    case "$value" in
      '"'*'"') value="$(printf '%s' "$value" | sed 's/^"//;s/"$//')" ;;
    esac

    # Strict character allowlist — no dangerous syntax can pass
    if ! printf '%s' "$value" | grep -qE "$_safe_value_pattern"; then
      echo "updatebtw: config $cfg contains invalid characters in: $line" >&2
      exec 8<&-
      return 1
    fi

    # Per-key validation — enforce expected format for each known key
    case "$key" in
      AUR_HELPER)
        case "$value" in yay|paru) ;; *) echo "updatebtw: config $cfg: AUR_HELPER must be 'yay' or 'paru'" >&2; exec 8<&-; return 1 ;; esac ;;
      UPDATE_FREQUENCY)
        case "$value" in daily|weekly|monthly) ;; *) echo "updatebtw: config $cfg: UPDATE_FREQUENCY must be 'daily', 'weekly', or 'monthly'" >&2; exec 8<&-; return 1 ;; esac ;;
      RUN_AT_BOOT|ENABLE_REFLECTOR|SILENT_BOOT)
        case "$value" in true|false) ;; *) echo "updatebtw: config $cfg: $key must be 'true' or 'false'" >&2; exec 8<&-; return 1 ;; esac ;;
      UPDATE_TIME)
        if ! printf '%s' "$value" | grep -qE '^[0-2][0-9]:[0-5][0-9]$'; then
          echo "updatebtw: config $cfg: UPDATE_TIME must be HH:MM format" >&2; exec 8<&-; return 1
        fi ;;
      REFLECTOR_INTERVAL)
        if ! printf '%s' "$value" | grep -qE '^[0-9]+$'; then
          echo "updatebtw: config $cfg: REFLECTOR_INTERVAL must be a number" >&2; exec 8<&-; return 1
        fi ;;
      REFLECTOR_COUNTRY)
        if ! printf '%s' "$value" | grep -qE '^[a-zA-Z0-9 .,-]+$'; then
          echo "updatebtw: config $cfg: REFLECTOR_COUNTRY contains invalid characters" >&2; exec 8<&-; return 1
        fi ;;
      REFLECTOR_PROTOCOL)
        case "$value" in https|http|rsync) ;; *) echo "updatebtw: config $cfg: REFLECTOR_PROTOCOL must be 'https', 'http', or 'rsync'" >&2; exec 8<&-; return 1 ;; esac ;;
      BLACKLIST_MODULES)
        if ! printf '%s' "$value" | grep -qE '^[a-zA-Z0-9_,]+$'; then
          echo "updatebtw: config $cfg: BLACKLIST_MODULES contains invalid characters" >&2; exec 8<&-; return 1
        fi ;;
      AUR_USER|FLATPAK_USER)
        if ! printf '%s' "$value" | grep -qE '^[a-z_][a-z0-9_-]*$'; then
          echo "updatebtw: config $cfg: $key contains invalid characters" >&2; exec 8<&-; return 1
        fi ;;
    esac

    # Set variable directly — never source the file
    case "$key" in
      AUR_HELPER)        AUR_HELPER="$value" ;;
      UPDATE_FREQUENCY)  UPDATE_FREQUENCY="$value" ;;
      UPDATE_TIME)       UPDATE_TIME="$value" ;;
      RUN_AT_BOOT)       RUN_AT_BOOT="$value" ;;
      ENABLE_REFLECTOR)  ENABLE_REFLECTOR="$value" ;;
      REFLECTOR_COUNTRY) REFLECTOR_COUNTRY="$value" ;;
      REFLECTOR_PROTOCOL) REFLECTOR_PROTOCOL="$value" ;;
      REFLECTOR_INTERVAL) REFLECTOR_INTERVAL="$value" ;;
      SILENT_BOOT)       SILENT_BOOT="$value" ;;
      BLACKLIST_MODULES) BLACKLIST_MODULES="$value" ;;
      AUR_USER)          AUR_USER="$value" ;;
      FLATPAK_USER)      FLATPAK_USER="$value" ;;
    esac
  done

  exec 8<&-
}

read_config() {
  _safe_read_config "$UPDATERBTW_CONFIG"
}

write_config() {
  local config_dir
  config_dir="$(dirname "$UPDATERBTW_CONFIG")"
  mkdir -p "$config_dir"
  local default_flatpak_user="${SUDO_USER:-}"
  [ -z "$default_flatpak_user" ] && default_flatpak_user="$(id -un)"

  # Sanitize values: strip double quotes and newlines to prevent heredoc injection
  local s_aur_helper s_freq s_time s_boot s_reflector s_country s_protocol s_interval s_silent s_modules s_aur_user s_flatpak_user
  s_aur_helper="${AUR_HELPER:-yay}"
  s_aur_helper="${s_aur_helper//\"/}"
  s_aur_helper="${s_aur_helper//$'\n'/}"
  s_freq="${UPDATE_FREQUENCY:-weekly}"
  s_freq="${s_freq//\"/}"
  s_freq="${s_freq//$'\n'/}"
  s_time="${UPDATE_TIME:-06:00}"
  s_time="${s_time//\"/}"
  s_time="${s_time//$'\n'/}"
  s_boot="${RUN_AT_BOOT:-false}"
  s_boot="${s_boot//\"/}"
  s_boot="${s_boot//$'\n'/}"
  s_reflector="${ENABLE_REFLECTOR:-true}"
  s_reflector="${s_reflector//\"/}"
  s_reflector="${s_reflector//$'\n'/}"
  s_country="${REFLECTOR_COUNTRY:-United States}"
  s_country="${s_country//\"/}"
  s_country="${s_country//$'\n'/}"
  s_protocol="${REFLECTOR_PROTOCOL:-https}"
  s_protocol="${s_protocol//\"/}"
  s_protocol="${s_protocol//$'\n'/}"
  s_interval="${REFLECTOR_INTERVAL:-30}"
  s_interval="${s_interval//\"/}"
  s_interval="${s_interval//$'\n'/}"
  s_silent="${SILENT_BOOT:-false}"
  s_silent="${s_silent//\"/}"
  s_silent="${s_silent//$'\n'/}"
  s_modules="${BLACKLIST_MODULES:-sp5100_tco}"
  s_modules="${s_modules//\"/}"
  s_modules="${s_modules//$'\n'/}"
  s_aur_user="${AUR_USER:-aur_builder}"
  s_aur_user="${s_aur_user//\"/}"
  s_aur_user="${s_aur_user//$'\n'/}"
  s_flatpak_user="${FLATPAK_USER:-$default_flatpak_user}"
  s_flatpak_user="${s_flatpak_user//\"/}"
  s_flatpak_user="${s_flatpak_user//$'\n'/}"

  # Use printf instead of heredoc to avoid interpolation issues
  {
    printf '# updatebtw configuration\n'
    printf '# Generated by updatebtw installer\n'
    printf '\n'
    printf 'AUR_HELPER="%s"\n' "$s_aur_helper"
    printf 'UPDATE_FREQUENCY="%s"\n' "$s_freq"
    printf 'UPDATE_TIME="%s"\n' "$s_time"
    printf 'RUN_AT_BOOT="%s"\n' "$s_boot"
    printf 'ENABLE_REFLECTOR="%s"\n' "$s_reflector"
    printf 'REFLECTOR_COUNTRY="%s"\n' "$s_country"
    printf 'REFLECTOR_PROTOCOL="%s"\n' "$s_protocol"
    printf 'REFLECTOR_INTERVAL="%s"\n' "$s_interval"
    printf 'SILENT_BOOT="%s"\n' "$s_silent"
    printf 'BLACKLIST_MODULES="%s"\n' "$s_modules"
    printf 'AUR_USER="%s"\n' "$s_aur_user"
    printf 'FLATPAK_USER="%s"\n' "$s_flatpak_user"
  } > "$UPDATERBTW_CONFIG"
  chmod 600 "$UPDATERBTW_CONFIG"
  chown root:root "$UPDATERBTW_CONFIG" 2>/dev/null || true
}

validate_config() {
  local errors=""
  case "${AUR_HELPER:-yay}" in
    yay|paru) ;;
    *) errors="${errors}error: AUR_HELPER must be 'yay' or 'paru' (got: ${AUR_HELPER})\n" ;;
  esac
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily|weekly|monthly) ;;
    *) errors="${errors}error: UPDATE_FREQUENCY must be 'daily', 'weekly', or 'monthly' (got: ${UPDATE_FREQUENCY})\n" ;;
  esac
  if [ -n "${AUR_USER:-}" ]; then
    local aur_uid
    aur_uid="$(id -u "$AUR_USER" 2>/dev/null)" || true
    if [ -n "$aur_uid" ] && [ "$aur_uid" -ge 1000 ] 2>/dev/null; then
      local aur_shell
      aur_shell="$(getent passwd "$AUR_USER" 2>/dev/null | cut -d: -f7)"
      case "$aur_shell" in
        */nologin|*/false) ;;
        *)
          errors="${errors}error: AUR_USER '$AUR_USER' appears to be a login user (UID $aur_uid). Use a dedicated system account.\n"
          ;;
      esac
    fi
  fi
  if [ -n "$errors" ]; then
    printf '%b' "$errors" >&2
    return 1
  fi
  return 0
}

calendar_from_config() {
  local time="${UPDATE_TIME:-06:00}"
  case "${UPDATE_FREQUENCY:-weekly}" in
    daily)   echo "*-*-* ${time}:00" ;;
    weekly)  echo "Mon *-*-* ${time}:00" ;;
    monthly) echo "*-*-01 ${time}:00" ;;
  esac
}

# === backup module ===
# updatebtw backup module

UPDATERBTW_BACKUP_DIR="${UPDATERBTW_BACKUP_DIR:-/var/lib/updatebtw/backups}"
UPDATERBTW_BACKUP_KEEP="${UPDATERBTW_BACKUP_KEEP:-10}"
UPDATERBTW_BACKUP_MANIFEST="${UPDATERBTW_BACKUP_MANIFEST:-/var/lib/updatebtw/backups/.manifest}"

backup_file() {
  local src="$1"
  [ -f "$src" ] || return 1
  [ ! -L "$src" ] || { echo "updatebtw: $src is a symlink, refusing" >&2; return 1; }
  mkdir -p "$UPDATERBTW_BACKUP_DIR"
  chmod 700 "$UPDATERBTW_BACKUP_DIR"
  local name
  name="$(basename "$src")"
  local ts rand
  ts="$(date "+%Y%m%d_%H%M%S")"
  rand="$(head -c 4 /dev/urandom | od -An -tx1 | tr -d ' \n')"
  local backup_path="$UPDATERBTW_BACKUP_DIR/${name}.${ts}.${rand}"
  cp -a "$src" "$backup_path"
  chmod 600 "$backup_path"
  chown root:root "$backup_path" 2>/dev/null || true

  mkdir -p "$(dirname "$UPDATERBTW_BACKUP_MANIFEST")"
  local hash perms owner group
  hash="$(sha256sum "$backup_path" | awk '{print $1}')"
  perms="$(stat -c '%a' "$src")"
  owner="$(stat -c '%u' "$src")"
  group="$(stat -c '%g' "$src")"
  local tmp_manifest tmp_hashes
  tmp_manifest="$(mktemp "${UPDATERBTW_BACKUP_MANIFEST}.XXXXXX")"
  tmp_hashes="$(mktemp "${UPDATERBTW_BACKUP_MANIFEST}.hashes.XXXXXX")"
  if [ -f "$UPDATERBTW_BACKUP_MANIFEST" ]; then
    cp "$UPDATERBTW_BACKUP_MANIFEST" "$tmp_manifest"
  fi
  if [ -f "${UPDATERBTW_BACKUP_MANIFEST}.hashes" ]; then
    cp "${UPDATERBTW_BACKUP_MANIFEST}.hashes" "$tmp_hashes"
  fi
  grep -qxF "$src" "$tmp_manifest" 2>/dev/null || echo "$src" >> "$tmp_manifest"
  echo "$src $hash $perms $owner $group" >> "$tmp_hashes"
  mv -f "$tmp_manifest" "$UPDATERBTW_BACKUP_MANIFEST"
  mv -f "$tmp_hashes" "${UPDATERBTW_BACKUP_MANIFEST}.hashes"
  chmod 600 "$UPDATERBTW_BACKUP_MANIFEST" 2>/dev/null || true
  chmod 600 "${UPDATERBTW_BACKUP_MANIFEST}.hashes" 2>/dev/null || true

  _rotate_backups "$name"
}

restore_file() {
  local src="$1"

  if [ -f "$UPDATERBTW_BACKUP_MANIFEST" ]; then
    if ! grep -qxF "$src" "$UPDATERBTW_BACKUP_MANIFEST"; then
      echo "updatebtw: $src has no backup, refusing restore" >&2
      return 1
    fi
  fi

  local name
  name="$(basename "$src")"
  local latest
  latest="$(ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null | head -1)"
  [ -n "$latest" ] || return 1

  if [ -f "${UPDATERBTW_BACKUP_MANIFEST}.hashes" ]; then
    local expected_hash
    expected_hash="$(grep "^$src " "${UPDATERBTW_BACKUP_MANIFEST}.hashes" | tail -1 | awk '{print $2}')"
    if [ -n "$expected_hash" ]; then
      local actual_hash
      actual_hash="$(sha256sum "$latest" | awk '{print $1}')"
      if [ "$actual_hash" != "$expected_hash" ]; then
        echo "updatebtw: backup integrity check failed for $src" >&2
        return 1
      fi
    fi
  fi

  cp -a "$latest" "$src"

  if [ -f "${UPDATERBTW_BACKUP_MANIFEST}.hashes" ]; then
    local manifest_line
    manifest_line="$(grep "^$src " "${UPDATERBTW_BACKUP_MANIFEST}.hashes" | tail -1)"
    if [ -n "$manifest_line" ]; then
      local r_perms r_owner r_group
      r_perms="$(printf '%s' "$manifest_line" | awk '{print $3}')"
      r_owner="$(printf '%s' "$manifest_line" | awk '{print $4}')"
      r_group="$(printf '%s' "$manifest_line" | awk '{print $5}')"
      if [ -n "$r_perms" ] && printf '%s' "$r_perms" | grep -qE '^[0-7]{3,4}$'; then
        chmod "$r_perms" "$src"
      fi
      if [ -n "$r_owner" ] && [ -n "$r_group" ]; then
        chown "$r_owner:$r_group" "$src" 2>/dev/null || true
      fi
    fi
  fi
}

list_backups() {
  local name="${1:-}"
  if [ -n "$name" ]; then
    find "$UPDATERBTW_BACKUP_DIR" -maxdepth 1 -name "${name}.*" -printf '%f\n' 2>/dev/null | sort -r || true
  else
    find "$UPDATERBTW_BACKUP_DIR" -maxdepth 1 -type f -printf '%f\n' 2>/dev/null | sort -r || true
  fi
}

_rotate_backups() {
  local name="$1"
  local keep="${UPDATERBTW_BACKUP_KEEP:-10}"
  ls -t "$UPDATERBTW_BACKUP_DIR/${name}."* 2>/dev/null \
    | tail -n +$((keep + 1)) \
    | xargs rm -f 2>/dev/null || true
}

_cleanup_old_backups() {
  [ -d "$UPDATERBTW_BACKUP_DIR" ] || return 0
  find "$UPDATERBTW_BACKUP_DIR" -type f -mtime +60 -delete 2>/dev/null || true
}

# === silent-boot module ===
# updatebtw silent boot module

BLACKLIST_MODULES="${BLACKLIST_MODULES:-sp5100_tco}"

detect_bootloader() {
  [ -f /boot/loader/loader.conf ] && echo "systemd-boot" && return 0
  [ -f /etc/default/grub ] && echo "grub" && return 0
  echo "unknown"
  return 0
}

set_kernel_options() {
  local entries_dir="${1:-/boot/loader/entries}"
  local kernel_options="${2:-quiet loglevel=3 vt.global_cursor_default=0 systemd.show_status=auto rd.udev.log_level=3}"
  if [ -n "$BLACKLIST_MODULES" ]; then
    kernel_options="$kernel_options modprobe.blacklist=$BLACKLIST_MODULES"
  fi

  read -ra option_tokens <<< "$kernel_options"
  local option_keys=()
  local token
  for token in "${option_tokens[@]}"; do
    option_keys+=("${token%%=*}")
  done

  [ -d "$entries_dir" ] || return 0
  local entry
  for entry in "$entries_dir"/*; do
    [ -f "$entry" ] || continue
    backup_file "$entry" 2>/dev/null || true

    local tmpfile
    tmpfile="$(mktemp /tmp/updatebtw-entry.XXXXXX)"
    chmod 644 "$tmpfile"
    chown root:root "$tmpfile"
    local line

    while IFS= read -r line; do
      read -ra line_tokens <<< "$line"
      if [ "${line_tokens[0]}" = "options" ]; then
        local out_line=""
        local token2 key2 skip
        for token2 in "${line_tokens[@]}"; do
          key2="${token2%%=*}"
          skip=false
          local k
          for k in "${option_keys[@]}"; do
            if [ "$key2" = "$k" ]; then
              skip=true
              break
            fi
          done
          if ! $skip; then
            out_line="$out_line$token2 "
          fi
        done
        out_line="$out_line$kernel_options"
        printf '%s\n' "$out_line" >> "$tmpfile"
      else
        printf '%s\n' "$line" >> "$tmpfile"
      fi
    done < "$entry"

    # Preserve original ownership/permissions, then atomic replace
    local orig_perms orig_owner orig_group
    orig_perms="$(stat -c '%a' "$entry" 2>/dev/null || echo "644")"
    orig_owner="$(stat -c '%u' "$entry" 2>/dev/null || echo "0")"
    orig_group="$(stat -c '%g' "$entry" 2>/dev/null || echo "0")"
    chmod "$orig_perms" "$tmpfile"
    chown "$orig_owner:$orig_group" "$tmpfile"
    mv -f "$tmpfile" "$entry"
  done
}

set_grub_silent() {
  local grub_cfg="${1:-/etc/default/grub}"
  [ -f "$grub_cfg" ] || return 0

  backup_file "$grub_cfg" 2>/dev/null || true

  local tmpfile
  tmpfile="$(mktemp /tmp/updatebtw-grub.XXXXXX)"
  chmod 644 "$tmpfile"
  chown root:root "$tmpfile"

  local has_default=false has_timeout=false has_recordfail=false

  while IFS= read -r line; do
    local key="${line%%=*}"
    key="${key## }"
    case "$key" in
      GRUB_DEFAULT)
        printf 'GRUB_DEFAULT=0\n' >> "$tmpfile"
        has_default=true
        ;;
      GRUB_TIMEOUT)
        printf 'GRUB_TIMEOUT=0\n' >> "$tmpfile"
        has_timeout=true
        ;;
      GRUB_RECORDFAIL_TIMEOUT)
        printf 'GRUB_RECORDFAIL_TIMEOUT=10\n' >> "$tmpfile"
        has_recordfail=true
        ;;
      *)
        printf '%s\n' "$line" >> "$tmpfile"
        ;;
    esac
  done < "$grub_cfg"

  if ! $has_default; then
    printf 'GRUB_DEFAULT=0\n' >> "$tmpfile"
  fi
  if ! $has_timeout; then
    printf 'GRUB_TIMEOUT=0\n' >> "$tmpfile"
  fi
  if ! $has_recordfail; then
    printf 'GRUB_RECORDFAIL_TIMEOUT=10\n' >> "$tmpfile"
  fi

  # Preserve original ownership/permissions, then atomic replace
  local orig_perms orig_owner orig_group
  orig_perms="$(stat -c '%a' "$grub_cfg" 2>/dev/null || echo "644")"
  orig_owner="$(stat -c '%u' "$grub_cfg" 2>/dev/null || echo "0")"
  orig_group="$(stat -c '%g' "$grub_cfg" 2>/dev/null || echo "0")"
  chmod "$orig_perms" "$tmpfile"
  chown "$orig_owner:$orig_group" "$tmpfile"
  mv -f "$tmpfile" "$grub_cfg"

  if command -v grub-mkconfig >/dev/null 2>&1; then
    grub-mkconfig -o /boot/grub/grub.cfg 2>/dev/null || true
  fi
}

set_printk() {
  local dest="${1:-/etc/sysctl.d/20-quiet-printk.conf}"
  local dest_dir
  dest_dir="$(dirname "$dest")"
  mkdir -p "$dest_dir"
  backup_file "$dest" 2>/dev/null || true
  printf 'kernel.printk = 3 3 3 3\n' > "$dest"
}

patch_mkinitcpio() {
  local src="${1:-/etc/mkinitcpio.conf}"
  [ -f "$src" ] || return 0
  backup_file "$src" 2>/dev/null || true

  local tmpfile
  tmpfile="$(mktemp /tmp/updatebtw-mkinitcpio.XXXXXX)"
  chmod 644 "$tmpfile"
  chown root:root "$tmpfile"
  local line

  while IFS= read -r line; do
    local key="${line%%=*}"
    key="${key## }"
    if [ "$key" = "HOOKS" ]; then
      local result="" trailing_paren="" token
      for token in $line; do
        local base="$token" has_paren=false
        case "$token" in
          *")")
            base="${token%)}"
            has_paren=true
            ;;
        esac
        case "$base" in
          udev)
            result="$result systemd"
            $has_paren && trailing_paren=")"
            ;;
          fsck)
            $has_paren && trailing_paren=")"
            continue
            ;;
          *)
            result="$result $base"
            $has_paren && trailing_paren=")"
            ;;
        esac
      done
      line="${result# }${trailing_paren}"
      printf '%s\n' "$line" >> "$tmpfile"
    else
      printf '%s\n' "$line" >> "$tmpfile"
    fi
  done < "$src"

  # Preserve original ownership/permissions, then atomic replace
  local orig_perms orig_owner orig_group
  orig_perms="$(stat -c '%a' "$src" 2>/dev/null || echo "644")"
  orig_owner="$(stat -c '%u' "$src" 2>/dev/null || echo "0")"
  orig_group="$(stat -c '%g' "$src" 2>/dev/null || echo "0")"
  chmod "$orig_perms" "$tmpfile"
  chown "$orig_owner:$orig_group" "$tmpfile"
  mv -f "$tmpfile" "$src"
}

patch_fsck_services() {
  local units=("$@")
  if [ ${#units[@]} -eq 0 ]; then
    units=(systemd-fsck@.service systemd-fsck-root.service)
  fi

  local unit
  for unit in "${units[@]}"; do
    local name="${unit%.service}"
    name="${name##*/}"
    local override_dir="/etc/systemd/system/${name}.service.d"
    mkdir -p "$override_dir"
    local override_file="$override_dir/silent.conf"

    if [ -f "$override_file" ] && grep -q 'StandardOutput=null' "$override_file" 2>/dev/null; then
      continue
    fi

    cat > "$override_file" << 'EOF'
[Service]
StandardOutput=null
StandardError=journal+console
EOF
  done
}

silent_boot() {
  local bootloader
  bootloader="$(detect_bootloader)"
  case "$bootloader" in
    systemd-boot)
      if [ ! -d /boot/loader/entries ] || [ -z "$(ls /boot/loader/entries/*.conf 2>/dev/null)" ]; then
        echo "Warning: No systemd-boot entries found — skipping kernel option changes" >&2
      else
        set_kernel_options
      fi
      ;;
    grub)
      if [ ! -f /etc/default/grub ]; then
        echo "Warning: GRUB config not found — skipping GRUB changes" >&2
      else
        set_grub_silent
      fi
      ;;
    unknown)
      echo "Warning: Unknown bootloader — skipping bootloader-specific changes"
      ;;
  esac

  set_printk
  patch_mkinitcpio
  patch_fsck_services

  if [ -f /etc/mkinitcpio.conf ] && [ -f /boot/vmlinuz-linux ]; then
    mkinitcpio -P || {
      echo "ERROR: mkinitcpio failed — restoring backup of mkinitcpio.conf" >&2
      restore_file /etc/mkinitcpio.conf 2>/dev/null || true
      return 1
    }
  fi

  touch ~root/.hushlogin
  touch ~"${SUDO_USER:-$(id -un)}"/.hushlogin 2>/dev/null || true

  systemctl unmask systemd-journald-audit.socket 2>/dev/null || true
  systemctl stop systemd-journald-audit.socket 2>/dev/null || true
  systemctl disable systemd-journald-audit.socket 2>/dev/null || true
  systemctl mask systemd-journald-audit.socket 2>/dev/null || true
}

# === updater module ===
# updatebtw updater module

UPDATERBTW_STATE_DIR="${UPDATERBTW_STATE_DIR:-/var/lib/updatebtw}"
: "${UPDATERBTW_MIN_UPDATE_INTERVAL:=300}"
_update_lock_fd=""

_check_rate_limit() {
  local state_file="$UPDATERBTW_STATE_DIR/last_update"
  local lock_file="$UPDATERBTW_STATE_DIR/update.lock"
  mkdir -p "$UPDATERBTW_STATE_DIR"
  chmod 700 "$UPDATERBTW_STATE_DIR"

  exec 8> "$lock_file"
  chmod 600 "$lock_file"
  if ! flock -n 8; then
    _notify error "Update In Progress" "Another update is already running"
    return 1
  fi
  _update_lock_fd=8

  if [ -f "$state_file" ]; then
    local last_update now delta
    last_update="$(cat "$state_file")"
    now="$(date "+%s")"
    delta=$(( now - last_update ))
    if [ "$delta" -lt "$UPDATERBTW_MIN_UPDATE_INTERVAL" ]; then
      _notify error "Update Throttled" "Last update was $(( delta ))s ago, minimum interval is ${UPDATERBTW_MIN_UPDATE_INTERVAL}s"
      return 1
    fi
  fi

  date "+%s" > "$state_file"
  chmod 600 "$state_file"
  return 0
}

update_packages() {
  trap '_notify critical "updatebtw" "Shutdown blocked — system update in progress, please wait"' SIGTERM
  read_config

  if ! _check_rate_limit; then
    return 1
  fi

  _cleanup_old_backups 2>/dev/null || true
  _cleanup_old_logs 2>/dev/null || true

  if [ -e /var/lib/pacman/db.lck ]; then
    _notify error "Update Failed" "/var/lib/pacman/db.lck exists"
    return 1
  fi

  local pacman_lock="$UPDATERBTW_STATE_DIR/pacman.lock"
  exec 7> "$pacman_lock"
  if ! flock -n 7; then
    _notify error "Update Failed" "Another pacman process holds the database lock"
    return 1
  fi

  if [ "${ENABLE_REFLECTOR:-true}" = "true" ]; then
    _update_mirrorlist || true
  fi

  _notify info "updatebtw" "Starting system update"
  local helper="${AUR_HELPER:-yay}"
  local aur_user="${AUR_USER:-aur_builder}"
  case "$helper" in
    yay)  _run_as_user "$aur_user" yay -Syyuu --noconfirm ;;
    paru) _run_as_user "$aur_user" paru -Syyuu --noconfirm ;;
  esac

  local exit_code=$?
  if [ $exit_code -ne 0 ]; then
    _notify error "Update Failed" "AUR helper exited with code $exit_code"
    return $exit_code
  fi

  if command -v flatpak >/dev/null 2>&1; then
    local flatpak_user="${FLATPAK_USER:-}"
    if [ -z "$flatpak_user" ]; then
      flatpak_user="${SUDO_USER:-}"
    fi
    if [ -z "$flatpak_user" ]; then
      flatpak_user="$(loginctl list-sessions --no-legend 2>/dev/null | awk '{print $2}' | head -1)"
      [ -n "$flatpak_user" ] && flatpak_user="$(id -un "$flatpak_user" 2>/dev/null)" || flatpak_user=""
    fi
    [ -z "$flatpak_user" ] && flatpak_user="$aur_user"
    _run_as_user "$flatpak_user" flatpak update --noninteractive || {
      _notify error "Flatpak Update Failed" "flatpak exited with code $?"
      return 1
    }
  fi

  _notify success "updatebtw" "Update complete"
  [ -n "$_update_lock_fd" ] && flock -u "$_update_lock_fd" 2>/dev/null || true
  flock -u 7 2>/dev/null || true
  rm -f "$pacman_lock" 2>/dev/null || true
}

_update_mirrorlist() {
  local mirrorlist="/etc/pacman.d/mirrorlist"
  local interval_days="${REFLECTOR_INTERVAL:-30}"
  # Clamp to sane bounds to prevent overflow or bypass
  if ! [ "$interval_days" -ge 0 ] 2>/dev/null || ! [ "$interval_days" -le 3650 ] 2>/dev/null; then
    interval_days=30
  fi
  local interval=$(( interval_days * 86400 ))

  if [ -f "$mirrorlist" ]; then
    local last_update
    last_update="$(date -r "$mirrorlist" "+%s")"
    local now
    now="$(date "+%s")"
    local delta=$(( now - last_update ))
    if [ $delta -lt $interval ]; then
      return 0
    fi
  fi

  backup_file "$mirrorlist"
  _notify info "updatebtw" "Updating mirrorlist via reflector"
  if ! timeout 120 reflector --save "$mirrorlist" \
       --country "${REFLECTOR_COUNTRY:-United States}" \
       --protocol "${REFLECTOR_PROTOCOL:-https}" \
       --latest 5 \
       --sort age \
       --age 12 \
       --connection-timeout 10; then
    _notify error "Reflector Failed" "Mirrorlist update failed"
    return 1
  fi
}

_notify() {
  local type="$1"
  local summary="$2"
  local body="$3"
  if [ "$type" = "error" ] && [ -n "$UPDATERBTW_LOG_FILE" ]; then
    body="$body — see $UPDATERBTW_LOG_FILE"
  fi
  echo "[$type] $summary: $body"
  if ! command -v notify-send >/dev/null 2>&1; then
    return 0
  fi

  local urgency="normal"
  local icon="dialog-information"
  case "$type" in
    error)    urgency="critical"; icon="dialog-error" ;;
    success)  urgency="normal";   icon="dialog-information" ;;
    info)     urgency="low";      icon="dialog-information" ;;
    critical) urgency="critical"; icon="dialog-warning" ;;
  esac

  local target_user="${SUDO_USER:-}"
  if [ -z "$target_user" ]; then
    target_user="$(loginctl list-sessions --no-legend 2>/dev/null | while read -r sid uid rest; do
      local stype
      stype="$(loginctl show-session "$sid" -p Type --value 2>/dev/null)"
      if [ "$stype" = "x11" ] || [ "$stype" = "wayland" ]; then
        id -un "$uid" 2>/dev/null && break
      fi
    done)"
    [ -z "$target_user" ] && target_user="$(loginctl list-sessions --no-legend 2>/dev/null | awk '{print $2}' | head -1)"
    [ -n "$target_user" ] && target_user="$(id -un "$target_user" 2>/dev/null)" || target_user=""
  fi

  if [ -n "$target_user" ]; then
    local uid
    uid="$(id -u "$target_user" 2>/dev/null)" || return 0

    case "$uid" in
      ''|*[!0-9]*) return 0 ;;
    esac
    if [ "$uid" -lt 1000 ] || [ "$uid" -gt 60000 ]; then
      return 0
    fi

    local bus_path="/run/user/$uid/bus"
    if [ -S "$bus_path" ]; then
      if [ "$(id -un)" = "$target_user" ]; then
        notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
      elif command -v runuser >/dev/null 2>&1; then
        runuser -u "$target_user" -- env \
          XDG_RUNTIME_DIR="/run/user/$uid" \
          DBUS_SESSION_BUS_ADDRESS="unix:path=$bus_path" \
          notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
      fi
    fi
  else
    notify-send -i "$icon" -u "$urgency" -a "updatebtw" "$summary" "$body" 2>/dev/null || true
  fi
  return 0
}

_run_as_user() {
  local user="$1"
  shift
  for arg in "$@"; do
    case "$arg" in
      *'$('*|*'`'*|*';'*|*'&'*|*'|'*)
        echo "updatebtw: unsafe argument detected: $arg" >&2
        return 1
        ;;
    esac
  done
  if [ "$(id -un)" = "$user" ]; then
    "$@"
  elif command -v runuser >/dev/null 2>&1; then
    runuser -u "$user" -- "$@"
  elif command -v sudo >/dev/null 2>&1; then
    sudo -u "$user" -- "$@"
  else
    echo "updatebtw: cannot run as user '$user' — neither runuser nor sudo available" >&2
    return 1
  fi
}

_cleanup_old_logs() {
  local log_dir="${UPDATERBTW_LOG_DIR:-/var/log/updatebtw}"
  [ -d "$log_dir" ] || return 0
  find "$log_dir" -type f -mtime +60 -delete 2>/dev/null || true
}

# payload: src/updatebtw -> /usr/bin/updatebtw
install_usr_bin_updatebtw() {
  local dest="/usr/bin/updatebtw"
  mkdir -p "$(dirname "$dest")"
  echo "" | base64 -d > "$dest"
  chmod 755 "$dest"
}

# payload: src/lib/config.sh -> /usr/lib/updatebtw/config.sh
install_usr_lib_updatebtw_config_sh() {
  local dest="/usr/lib/updatebtw/config.sh"
  mkdir -p "$(dirname "$dest")"
  echo "" | base64 -d > "$dest"
  chmod 644 "$dest"
}

# payload: src/lib/backup.sh -> /usr/lib/updatebtw/backup.sh
install_usr_lib_updatebtw_backup_sh() {
  local dest="/usr/lib/updatebtw/backup.sh"
  mkdir -p "$(dirname "$dest")"
  echo "" | base64 -d > "$dest"
  chmod 644 "$dest"
}

# payload: src/lib/updater.sh -> /usr/lib/updatebtw/updater.sh
install_usr_lib_updatebtw_updater_sh() {
